def _seed_api_limits(db, *, received_at: float, raw: dict | None = None) -> int:
    raw_json = json.dumps(raw if raw is not None else _SAMPLE_RAW)
    log_id, _ = run_async(
        schema.insert_log_api_limits(
            db,
            received_at=received_at,
            received_by="limits-fetcher",
            raw_response=raw_json,
        )
    )
    run_async(db.commit())
    return log_id


class TestLogApiLimitsEndpoint:
    def test_returns_rows(self, client, db) -> None:
        _seed_api_limits(db, received_at=100.0)
        _seed_api_limits(db, received_at=200.0)

        resp = client.get("/api/v2/log/api-limits")
        assert resp.status_code == 200
        body = resp.json()
        assert len(body) == 2
        assert body[0]["received_at"] == 100.0
        assert body[1]["received_at"] == 200.0
        assert body[0]["five_hour_utilization"] == 11.0
        assert body[0]["seven_day_utilization"] == 8.0
        assert body[0]["received_by"] == "limits-fetcher"
        # raw_response included by default on /log/* endpoints
        assert body[0]["raw_response"] is not None

    def test_filter_since_until(self, client, db) -> None:
        for t in (100.0, 200.0, 300.0):
            _seed_api_limits(db, received_at=t)

        resp = client.get("/api/v2/log/api-limits?since=150&until=250")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["received_at"] == 200.0

    def test_pagination(self, client, db) -> None:
        for t in (100.0, 110.0, 120.0):
            _seed_api_limits(db, received_at=t)

        resp = client.get("/api/v2/log/api-limits?limit=1&offset=1")
        body = resp.json()
        assert len(body) == 1
        assert body[0]["received_at"] == 110.0

    def test_invalid_limit_returns_422(self, client) -> None:
        resp = client.get("/api/v2/log/api-limits?limit=2000")
        assert resp.status_code == 422
